phase1.code:
using UnityEngine;

public class GameObjectExample : MonoBehaviour
{
    void Start()
    {
        // Create a GameObject
        GameObject cube = GameObject.CreatePrimitive(PrimitiveType.Cube);
        cube.name = "MyFirstCube";

        // Add a component
        Rigidbody rb = cube.AddComponent<Rigidbody>();

        // Access a component
        Transform trans = cube.transform;
        trans.position = new Vector3(0, 2, 0);

        // Log the GameObject's name
        Debug.Log("Created: " + cube.name);
        Debug.Log("Position: " + trans.position);
    }
}

phase2.brokenCode:
using UnityEngine;

public class ComponentError : MonoBehaviour
{
    void Start()
    {
        // Error: trying to get a component that doesn't exist
        Rigidbody rb = GetComponent<Rigidbody>();
        rb.AddForce(Vector3.up * 10);  // NullReferenceException!
    }
}

phase2.explanation:
This GameObject doesn't have a Rigidbody component, so `GetComponent<Rigidbody>()` returns `null`.

**The fix:**
```csharp
Rigidbody rb = GetComponent<Rigidbody>();
if (rb != null)
{
    rb.AddForce(Vector3.up * 10);
}
```

**Sharp-chan says:**
"Always check if a component exists before using it. It's a common beginner mistake, and it's easy to fix. Get used to using `if` checks."
